-- Create "model_entity" table
CREATE TABLE IF NOT EXISTS `model_entity` (`id` bigint unsigned NOT NULL COMMENT "ńŞ╗Úö«ID", `meta_id` bigint unsigned NOT NULL COMMENT "ŠĘíň×őňůâń┐íŠü» id", `name` varchar(128) NOT NULL COMMENT "ňÉŹšž░", `description` text NULL COMMENT "ŠĆĆŔ┐░", `default_params` json NOT NULL COMMENT "Ú╗śŔ«ĄňĆéŠĽ░", `scenario` bigint unsigned NOT NULL COMMENT "ŠĘíň×őň║öšöĘňť║ŠÖ»", `status` int NOT NULL DEFAULT 1 COMMENT "ŠĘíň×őšŐÂŠÇü", `created_at` bigint unsigned NOT NULL DEFAULT 0 COMMENT "Create Time in Milliseconds", `updated_at` bigint unsigned NOT NULL DEFAULT 0 COMMENT "Update Time in Milliseconds", `deleted_at` bigint unsigned NULL COMMENT "Delete Time in Milliseconds", PRIMARY KEY (`id`), INDEX `idx_scenario` (`scenario`), INDEX `idx_status` (`status`)) CHARSET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT "ŠĘíň×őń┐íŠü»";
-- Create "model_meta" table
CREATE TABLE IF NOT EXISTS `model_meta` (`id` bigint unsigned NOT NULL COMMENT "ńŞ╗Úö«ID", `model_name` varchar(128) NOT NULL COMMENT "ŠĘíň×őňÉŹšž░", `protocol` varchar(128) NOT NULL COMMENT "ŠĘíň×őňŹĆŔ««", `icon_uri` varchar(255) NOT NULL DEFAULT "" COMMENT "Icon URI", `capability` json NULL COMMENT "ŠĘíň×őŔâŻňŐŤ", `conn_config` json NULL COMMENT "ŠĘíň×őŔ┐×ŠÄąÚůŹšŻ«", `status` int NOT NULL DEFAULT 1 COMMENT "ŠĘíň×őšŐÂŠÇü", `description` varchar(2048) NOT NULL DEFAULT "" COMMENT "ŠĘíň×őŠĆĆŔ┐░", `created_at` bigint unsigned NOT NULL DEFAULT 0 COMMENT "Create Time in Milliseconds", `updated_at` bigint unsigned NOT NULL DEFAULT 0 COMMENT "Update Time in Milliseconds", `deleted_at` bigint unsigned NULL COMMENT "Delete Time in Milliseconds", `icon_url` varchar(255) NOT NULL DEFAULT "" COMMENT "Icon URL", PRIMARY KEY (`id`), INDEX `idx_status` (`status`)) CHARSET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT "ŠĘíň×őňůâń┐íŠü»";
-- Create "node_execution" table
CREATE TABLE IF NOT EXISTS `node_execution` (`id` bigint unsigned NOT NULL COMMENT "node execution id", `execute_id` bigint unsigned NOT NULL COMMENT "the workflow execute id this node execution belongs to", `node_id` varchar(128) NOT NULL COMMENT "node key", `node_name` varchar(128) NOT NULL COMMENT "name of the node", `node_type` varchar(128) NOT NULL COMMENT "the type of the node, in string", `created_at` bigint unsigned NOT NULL COMMENT "create time in millisecond", `status` tinyint unsigned NOT NULL COMMENT "1=waiting 2=running 3=success 4=fail", `duration` bigint unsigned NULL COMMENT "execution duration in millisecond", `input` mediumtext NULL COMMENT "actual input of the node", `output` mediumtext NULL COMMENT "actual output of the node", `raw_output` mediumtext NULL COMMENT "the original output of the node", `error_info` mediumtext NULL COMMENT "error info", `error_level` varchar(32) NULL COMMENT "level of the error", `input_tokens` bigint unsigned NULL COMMENT "number of input tokens", `output_tokens` bigint unsigned NULL COMMENT "number of output tokens", `updated_at` bigint unsigned NULL COMMENT "update time in millisecond", `composite_node_index` bigint unsigned NULL COMMENT "loop or batch's execution index", `composite_node_items` mediumtext NULL COMMENT "the items extracted from parent composite node for this index", `parent_node_id` varchar(128) NULL COMMENT "when as inner node for loop or batch, this is the parent node's key", `sub_execute_id` bigint unsigned NULL COMMENT "if this node is sub_workflow, the exe id of the sub workflow", `extra` mediumtext NULL COMMENT "extra info", PRIMARY KEY (`id`), INDEX `idx_execute_id_node_id` (`execute_id`, `node_id`), INDEX `idx_execute_id_parent_node_id` (`execute_id`, `parent_node_id`)) CHARSET utf8mb4 COLLATE utf8mb4_unicode_ci;
-- Create "online_database_info" table
CREATE TABLE IF NOT EXISTS `online_database_info` (`id` bigint unsigned NOT NULL COMMENT "ID", `app_id` bigint unsigned NULL COMMENT "App ID", `space_id` bigint unsigned NOT NULL COMMENT "Space ID", `related_draft_id` bigint unsigned NOT NULL COMMENT "The primary key ID of draft_database_info table", `is_visible` tinyint NOT NULL DEFAULT 1 COMMENT "Visibility: 0 invisible, 1 visible", `prompt_disabled` tinyint NOT NULL DEFAULT 0 COMMENT "Support prompt calls: 1 not supported, 0 supported", `table_name` varchar(255) NOT NULL COMMENT "Table name", `table_desc` varchar(256) NULL COMMENT "Table description", `table_field` text NULL COMMENT "Table field info", `creator_id` bigint NOT NULL DEFAULT 0 COMMENT "Creator ID", `icon_uri` varchar(255) NOT NULL COMMENT "Icon Uri", `physical_table_name` varchar(255) NULL COMMENT "The name of the real physical table", `rw_mode` bigint NOT NULL DEFAULT 1 COMMENT "Read and write permission modes: 1. Limited read and write mode 2. Read-only mode 3. Full read and write mode", `created_at` bigint unsigned NOT NULL DEFAULT 0 COMMENT "Create Time in Milliseconds", `updated_at` bigint unsigned NOT NULL DEFAULT 0 COMMENT "Update Time in Milliseconds", `deleted_at` datetime NULL COMMENT "Delete Time", PRIMARY KEY (`id`), INDEX `idx_space_app_creator_deleted` (`space_id`, `app_id`, `creator_id`, `deleted_at`)) CHARSET utf8mb4 COLLATE utf8mb4_general_ci COMMENT "online database info";
-- Create "plugin" table
